import networkx as nx
import numpy as np
import matplotlib.pyplot as plt
import pandas as pd
import pickle
import os

class GraphViz:
    def __init__(self, G: nx.MultiDiGraph, source_folder : str):
        self.stops = pd.read_csv(os.path.join(source_folder, "stops.txt"), encoding="UTF-8", low_memory=False)
        self.routes = pd.read_csv(os.path.join(source_folder, "routes.txt"), encoding="UTF-8", low_memory=False)
        self.G = G

    #ez a metodus kirajzolja a teljes halozatot
    #az elek jarattipusonkent mas szineket kapnak
    #a networkx beepitett grafrajzolo metodusait hasznalva egyszeruen abrazolhatunk hosszusagi es szelessegi koordinatak szerint
    def viz(self):
        pos = {row["stop_id"]: (row["stop_lon"], row["stop_lat"]) for _, row in self.stops.iterrows()}
        plt.figure(figsize=(12,12))

        bus_edges = [(u,v) for u, v, d in self.G.edges(data=True) if d["route_type"]==3]
        tram_edges = [(u,v) for u, v, d in self.G.edges(data=True) if d["route_type"]==0]
        metro_edges = [(u,v) for u, v, d in self.G.edges(data=True) if d["route_type"]==1]
        trolley_edges = [(u,v) for u, v, d in self.G.edges(data=True) if d["route_type"]==11]
        hev_edges = [(u,v) for u, v, d in self.G.edges(data=True) if d["route_type"]==109]
        transfer_edges = [(u,v) for u, v, d in self.G.edges(data=True) if d["route_id"] == "TRANSFER"]

        nx.draw_networkx_edges(self.G, pos, edgelist=bus_edges, edge_color = "blue", arrows = False, alpha=0.3)
        nx.draw_networkx_edges(self.G, pos, edgelist=tram_edges, edge_color = "yellow", arrows = False, alpha=0.3)
        nx.draw_networkx_edges(self.G, pos, edgelist=metro_edges, edge_color = "black", arrows = False, alpha=0.6)
        nx.draw_networkx_edges(self.G, pos, edgelist=trolley_edges, edge_color = "red", arrows = False, alpha=0.3)
        nx.draw_networkx_edges(self.G, pos, edgelist=hev_edges, edge_color = "green", arrows = False, alpha=0.3)
        nx.draw_networkx_edges(self.G, pos, edgelist=transfer_edges, edge_color = "gray", arrows = False, alpha=0.3)

        nx.draw_networkx_nodes(self.G, pos, node_size=2, node_color="#444444")
        plt.axis("off")
        plt.show()

    #ez a segedfv a 
    def get_edge_color(self, route_type, route_id):
        if route_id == "TRANSFER": #atszallasi el: szurke (semleges)
            return "gray"
        if route_type == 3: #busz: kek
            return "blue"
        if route_type == 0: #villamos: sarga
            return "yellow"
        if route_type == 1: #metro: fekete
            return "black"
        if route_type == 11: #troli: piros
            return "red"
        if route_type == 109: #hev: zold
            return "green"
        return "purple" #egyebkent lila

    #ez a metodus kirajzolja eloszor szurke keskeny elekkel a dijkstra altal felfedezett fenyot
    #majd rarajzolja a felfedezett legrovidebb utvonalat szinezve
    #input: dijkstra p tombje (dictionary) es maga a path, ami a reconstruct_path fv-nek az outputja
    def fenyo_viz(self, fenyo: dict, start, end, path):
        #eloszor epitunk egy start-fenyot.
        G = nx.MultiDiGraph()
        if not path:
            return None
        for node, edge in fenyo.items():
            parent = edge[0]
            if node != parent:
                G.add_edge(
                    parent,
                    node,
                    key = edge[3],
                    route_id = edge[3],
                    route_type=edge[4]
                )
            
        #kirajzoljuk szurkevel a felfedezett eleket
        pos = {str(row["stop_id"]): (row["stop_lon"], row["stop_lat"]) for _, row in self.stops.iterrows()}
        fig, ax = plt.subplots(figsize=(12,12))

        nx.draw_networkx_edges(G, pos, G.edges(data=True), edge_color="gray", arrows=False, alpha=0.3 )
        nx.draw_networkx_nodes(G, pos, node_size=2, node_color="#444444")
        #start es end csucsokat nagyban jeloljuk
        nx.draw_networkx_nodes(G, pos, nodelist=[start], node_size=20, node_color="blue")
        nx.draw_networkx_nodes(G, pos, nodelist=[end], node_size=20, node_color="red")

        plt.axis("off")
        #az output a reconstruct_path-bol belerak egy hurokelet az elso csucsra, ezt kiszurjuk
        it_counter = 0
        for step in path:
            #if it_counter ==0:
            #    it_counter+=1
            #    continue
            u = step[0]
            v = step[1]
            route_id = step[3]
            route_type = step[4]

            #segedfuggvenybol meghivjuk, hogy milyen szinu legyen az el
            color = self.get_edge_color(route_type, route_id)

            #kirajzoljuk az elet
            nx.draw_networkx_edges(
                G,
                pos,
                edgelist=[(u,v)],
                edge_color = color,
                arrows=False,
                width=2
            )
            plt.pause(0.2)
        plt.close(fig)
        return fig, ax
            

